#include <stdio.h>
#include <stdlib.h>
int main(){
    int T; if(scanf("%d",&T)!=1) return 0;
    while(T--){
        int N,K; scanf("%d %d",&N,&K);
        long long *arr = (long long*)malloc(sizeof(long long)*N);
        for(int i=0;i<N;i++) scanf("%lld",&arr[i]);
        long long cur=0;
        for(int i=0;i<K;i++) cur+=arr[i];
        long long best=cur;
        for(int i=K;i<N;i++){
            cur = cur - arr[i-K] + arr[i];
            if(cur>best) best=cur;
        }
        printf("%lld\n",best);
        free(arr);
    }
    return 0;
}

